const b = $input.first().json.body || $input.first().json;

function num(v, d) {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
}

const pDeltas = Array.isArray(b.p_deltas) ? b.p_deltas.map(Number).filter(Number.isFinite) : [];
const aDeltas = Array.isArray(b.a_deltas) ? b.a_deltas.map(Number).filter(Number.isFinite) : [];

const avg = arr => arr.length ? arr.reduce((s,x)=>s+x,0)/arr.length : 0;

const initial_P = num(b.initial_P, 0);
const initial_A = num(b.initial_A, 0);
const final_D = num(b.final_D, 0);

// final_X = initial_X + avg(3 deltas) * 0.5
const final_P = +(initial_P + avg(pDeltas) * 0.5).toFixed(4);
const final_A = +(initial_A + avg(aDeltas) * 0.5).toFixed(4);

const row = {
  session_id: String(b.session_id || ''),
  timestamp: new Date().toISOString(),
  initial_P,
  initial_A,
  final_P,
  final_A,
  final_D,
  matched_user_id: '',
  match_timestamp: '',
  match_ended_at: ''
};

if (!row.session_id) {
  throw new Error('session_id is required');
}

return [{ json: row }];
